import React, { useState } from 'react'

// Componente per tracciare singola serie
const SetTracker = ({
    setNumber,
    targetReps,
    targetWeight,
    actualReps,
    actualWeight,
    isCompleted,
    isActive,
    handleUpdateSet = () => { },
    handleSaveSet = () => { },
    onToggleComplete = () => { },
}) => {
    const [isEditing, setIsEditing] = useState(false);

    const handleSave = () => {
        setIsEditing(false);
        handleSaveSet();
    };

    const handleComplete = () => {
        setIsEditing(false);
        onToggleComplete(setNumber);
    };

    return (
        <div className={`current-session-item${isCompleted ? ' is-completed' : isActive ? ' active' : ''}`}>
            {/* Numero serie */}
            <div className="serie-counter-badge">{isCompleted ? <i className="far fa-circle-check"></i> : setNumber}</div>

            <div className="item-content d-flex align-items-center justify-content-between gap-3">
                <div className="data-serie-col">
                    {/* Peso */}
                    <div className="text-center">
                        <div className="heading-title">PESO (kg)</div>
                        {isEditing ? (
                            <div className="form-group">
                                <button
                                    onClick={() => handleUpdateSet(setNumber, 'actualWeight', actualWeight - 2.5)}
                                    className="btn btn-control-input"
                                >
                                    <i className="fas fa-minus"></i>
                                </button>
                                <input
                                    type="number"
                                    step="0.5"
                                    min="0"
                                    value={actualWeight}
                                    onChange={(e) => handleUpdateSet(setNumber, 'actualWeight', parseFloat(e.target.value) || 0)}
                                />
                                <button
                                    onClick={() => handleUpdateSet(setNumber, 'actualWeight', actualWeight + 2.5)}
                                    className="btn btn-control-input"
                                >
                                    <i className="fas fa-plus"></i>
                                </button>
                            </div>
                        ) : (
                            <div className="current-value">
                                {/* {actualWeight || tempWeight} */}
                                {actualWeight}
                                {/* {targetWeight && actualWeight !== targetWeight && ( */}
                                <span className="last-value-saved">/{targetWeight}</span>
                                {/* )} */}
                            </div>
                        )}
                    </div>

                    {/* Ripetizioni */}
                    <div className="text-center">
                        <div className="heading-title">REPS</div>
                        {isEditing ? (
                            <div className="form-group">
                                <button
                                    onClick={() => handleUpdateSet(setNumber, 'actualReps', actualReps - 1)}
                                    className="btn btn-control-input"
                                >
                                    <i className="fas fa-minus"></i>
                                </button>
                                <input
                                    type="number"
                                    min={0}
                                    value={actualReps}
                                    onChange={(e) => handleUpdateSet(setNumber, 'actualReps', parseInt(e.target.value) || 0)}
                                />
                                <button
                                    onClick={() => handleUpdateSet(setNumber, 'actualReps', actualReps + 1)}
                                    className="btn btn-control-input"
                                >
                                    <i className="fas fa-plus"></i>
                                </button>
                            </div>
                        ) : (
                            <div className="current-value">
                                {/* {actualReps || tempReps} */}
                                {actualReps}
                                {/* {targetReps && actualReps !== targetReps && ( */}
                                <span className="last-value-saved">/{targetReps}</span>
                                {/* )} */}
                            </div>
                        )}
                    </div>
                </div>

                {/* Azioni */}
                <div className="col-actions">
                    {isEditing ? (
                        <button
                            onClick={handleSave}
                            className="btn btn-primary btn-action"
                        >
                            <i className="fas fa-floppy-disk me-1"></i>Salva
                        </button>
                    ) : (
                        <button
                            onClick={() => setIsEditing(true)}
                            className="btn btn-edit transition-colors"
                        >
                            <i className="fas fa-pencil"></i>
                        </button>
                    )}

                    <button
                        onClick={handleComplete}
                        className={`btn btn-action btn-toggle-completed transition-colors ${isCompleted ? 'is-completed' : ''}`}
                        disabled={isCompleted}
                    >
                        {isCompleted ? <i className="far fa-circle-check me-1"></i> : <i className="far fa-circle me-1"></i>}
                        {isCompleted ? 'Fatto' : 'Completa'}
                    </button>
                </div>
            </div>

            {/* Indicatori di performance */}
            {/* todo per ora no */}
            {/* {isCompleted && actualReps && targetReps && (
                <div className="mt-2 flex items-center gap-2">
                    {actualReps >= targetReps ? (
                        <div className="flex items-center gap-1 text-green-600 text-xs">
                            <Flame className="w-3 h-3" />
                            <span className="font-medium">Obiettivo raggiunto!</span>
                        </div>
                    ) : (
                        <div className="flex items-center gap-1 text-orange-500 text-xs">
                            <Target className="w-3 h-3" />
                            <span className="font-medium">-{targetReps - actualReps} reps dall'obiettivo</span>
                        </div>
                    )}
                </div>
            )} */}
        </div>
    );
};

export default SetTracker;
