import React from 'react';
import {
    LineChart,
    Line,
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    ComposedChart
} from 'recharts';
import CustomTooltip from './CustomTooltip';

const ChartRenderer = ({ chartType, data }) => {
    const commonProps = {
        data,
        margin: { top: 5, right: 30, left: 20, bottom: 5 }
    };

    switch (chartType) {
        case 'combined':
            return (
                <ComposedChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#e0e0e0" />
                    <XAxis 
                        dataKey="sessionNumber" 
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        yAxisId="left"
                        label={{ value: 'Peso (kg)', angle: -90, position: 'insideLeft' }}
                    />
                    <YAxis 
                        yAxisId="right" 
                        orientation="right"
                        label={{ value: 'Ripetizioni', angle: 90, position: 'insideRight' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Bar 
                        yAxisId="left"
                        dataKey="avgWeight" 
                        fill="#cb3234" 
                        name="Peso Medio (kg)"
                        radius={[4, 4, 0, 0]}
                    />
                    <Line 
                        yAxisId="right"
                        type="monotone" 
                        dataKey="avgReps" 
                        stroke="#4a90e2" 
                        strokeWidth={2}
                        name="Ripetizioni Medie"
                        dot={{ r: 5 }}
                    />
                </ComposedChart>
            );

        case 'weight':
            return (
                <LineChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#e0e0e0" />
                    <XAxis 
                        dataKey="sessionNumber"
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        label={{ value: 'Peso (kg)', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Line 
                        type="monotone" 
                        dataKey="avgWeight" 
                        stroke="#cb3234" 
                        strokeWidth={3}
                        name="Peso Medio (kg)"
                        dot={{ r: 6 }}
                        activeDot={{ r: 8 }}
                    />
                    <Line 
                        type="monotone" 
                        dataKey="maxWeight" 
                        stroke="#ff6b6b" 
                        strokeWidth={2}
                        strokeDasharray="5 5"
                        name="Peso Massimo (kg)"
                        dot={{ r: 4 }}
                    />
                </LineChart>
            );

        case 'reps':
            return (
                <LineChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#e0e0e0" />
                    <XAxis 
                        dataKey="sessionNumber"
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        label={{ value: 'Ripetizioni', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Line 
                        type="monotone" 
                        dataKey="avgReps" 
                        stroke="#4a90e2" 
                        strokeWidth={3}
                        name="Ripetizioni Medie"
                        dot={{ r: 6 }}
                        activeDot={{ r: 8 }}
                    />
                    <Line 
                        type="monotone" 
                        dataKey="maxReps" 
                        stroke="#5dade2" 
                        strokeWidth={2}
                        strokeDasharray="5 5"
                        name="Ripetizioni Massime"
                        dot={{ r: 4 }}
                    />
                </LineChart>
            );

        case 'volume':
            return (
                <BarChart {...commonProps}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#e0e0e0" />
                    <XAxis 
                        dataKey="sessionNumber"
                        label={{ value: 'Sessione', position: 'insideBottom', offset: -5 }}
                    />
                    <YAxis 
                        label={{ value: 'Volume (kg)', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Bar 
                        dataKey="totalVolume" 
                        fill="#52c41a" 
                        name="Volume Totale (kg)"
                        radius={[8, 8, 0, 0]}
                    />
                </BarChart>
            );

        default:
            return null;
    }
};

const ChartContainer = ({ chartType, data }) => {
    return (
        <div className="chart-container">
            <ResponsiveContainer width="100%" height={300}>
                <ChartRenderer chartType={chartType} data={data} />
            </ResponsiveContainer>
        </div>
    );
};

export default ChartContainer;
