// src/features/user/userSlice.js
import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import { AuthService } from "../../services/auth.service";
import { hideLoader, showLoader } from "../loader/loaderSlice";
import { resetWorkout } from "../workout/workoutSlice";
import { ProfileService } from "../../services/profile.service";

const initialState = {
    // user: null,          // Contiene l'intero oggetto user
    // token: null,         // Contiene il token JWT o simile
    ...AuthService.getUser(),
    sessions: [],         // Sessioni attive dell'utente
    sessionsLoading: false, // Stato di caricamento delle sessioni
    status: 'idle',      // Stato della chiamata asincrona: 'idle', 'loading', 'succeded', 'failed'
    message: '',         // Messaggio di successo o errore
    errors: {}          // Errori di login o registrazione
};

// Thunk per la chiamata asincrona di login
export const loginUser = createAsyncThunk(
    'user/loginUser',
    async ({ email, password }, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader()); // Mostra il loader all'inizio
            const { data } = await AuthService.login({ email, password });
            //AuthService.setToken({ token: `Bearer ${data.data.access_token}` });
            AuthService.setUser(data.data);

            return data.data;
        } catch (error) {
            return rejectWithValue(error.response?.data.errors || error);
        } finally {
            dispatch(hideLoader());
        }
    }
);

// Thunk per la chiamata asincrona di logout
export const logoutUser = createAsyncThunk(
    'user/logoutUser',
    async (_, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader());
            await AuthService.logout(); // Effettua la chiamata di logout al backend, se esiste
            AuthService.resetToken();
            // Invio Dispatch per il reset del workout dell'utente
            dispatch(resetWorkout());

            return true; // Ritorna un valore indicativo di successo
        } catch (error) {
            AuthService.resetToken();
            return rejectWithValue(error.response?.data || "Logout fallito");
        } finally {
            dispatch(hideLoader());
        }
    }
);

// Thunk per la chiamata asincrona di registrazione
export const registerUser = createAsyncThunk(
    'user/registerUser',
    async ({ username, email, password, password_confirmation }, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader());
            const { data } = await AuthService.register({ username, email, password, password_confirmation });

            return data;
        } catch (error) {
            return rejectWithValue(error.response.data);
        } finally {
            dispatch(hideLoader());
        }
    }
);

export const updateUser = createAsyncThunk(
    'user/updateUser',
    async (formData, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader());
            const { data } = await ProfileService.updateProfile(formData);

            return data;
        } catch (error) {
            return rejectWithValue(error.response.data);
        } finally {
            dispatch(hideLoader());
        }
    }
);

// Thunk per ricaricare il profilo dall'API
export const fetchProfile = createAsyncThunk(
    'user/fetchProfile',
    async (_, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader());
            const { data } = await ProfileService.getProfile();

            // Salva il profilo nel localStorage
            if (data.data) {
                ProfileService.setUser(data.data);
            }

            return data;
        } catch (error) {
            return rejectWithValue(error.response?.data || 'Errore nel caricamento del profilo');
        } finally {
            dispatch(hideLoader());
        }
    }
);

// Formatta le informazioni del dispositivo
const formatDeviceInfo = (deviceInfo) => {
    if (!deviceInfo) return 'Dispositivo sconosciuto';

    const parts = [];
    if (deviceInfo.browser) parts.push(deviceInfo.browser);
    if (deviceInfo.platform) parts.push(deviceInfo.platform);

    return parts.length > 0 ? parts.join(' - ') : 'Dispositivo sconosciuto';
};

// Thunk per caricare le sessioni
export const fetchSessions = createAsyncThunk(
    'user/fetchSessions',
    async (_, { dispatch, rejectWithValue }) => {
        try {
            const { data } = await ProfileService.getSessions();
            const sessionsData = data.data || [];

            // Mappa i dati dal backend alla struttura attesa dalla vista
            const formattedSessions = sessionsData.map(session => ({
                id: session.id,
                device: formatDeviceInfo(session.device_info),
                ip: session.ip_address || 'IP non disponibile',
                deviceType: session.device_info?.device_type || 'Unknown',
                lastActivity: session.last_used_at || session.created_at,
                hasLastUsedAt: !!session.last_used_at,
                isCurrent: session.is_current || false
            }));

            return formattedSessions;
        } catch (error) {
            return rejectWithValue(error.response?.data || 'Errore nel caricamento delle sessioni');
        }
    }
);

const userSlice = createSlice({
    name: 'user',
    initialState,
    reducers: {
        /* logoutUser: (state) => {
            state.user = null;
            state.token = null;
            state.status = 'idle';
            state.errors = {};
        } */
        removeSession: (state, action) => {
            state.sessions = state.sessions.filter(session => session.id !== action.payload);
        },
        removeAllOtherSessions: (state) => {
            state.sessions = state.sessions.filter(session => session.isCurrent);
        },
        updateAvatar: (state, action) => {
            state.user.avatar_url = action.payload;
        },
    },
    extraReducers: (builder) => {
        builder
            // Login
            .addCase(loginUser.pending, (state) => {
                state.status = 'loading';
                state.errors = {};
            })
            .addCase(loginUser.fulfilled, (state, action) => {
                state.status = 'succeded';
                state.user = action.payload.user;
                state.token = action.payload.access_token;
                state.errors = {};
            })
            .addCase(loginUser.rejected, (state, action) => {
                state.status = 'failed';
                state.user = null;
                state.token = null;
                state.errors = action.payload || {};
            })
            // Logout
            .addCase(logoutUser.pending, (state) => {
                state.status = 'loading';
            })
            .addCase(logoutUser.fulfilled, (state) => {
                state.status = 'idle';
                state.user = null;
                state.token = null;
                state.errors = {};
                state.sessions = [];
            })
            .addCase(logoutUser.rejected, (state, action) => {
                state.status = 'failed';
                state.user = null;
                state.token = null;
                state.errors = action.payload || {};
                state.sessions = [];
            })
            // Registrazione
            .addCase(registerUser.pending, (state) => {
                state.status = 'loading';
                state.errors = {};
            })
            .addCase(registerUser.fulfilled, (state, action) => {
                state.status = 'succeded';
                state.user = action.payload.data;
                state.message = action.payload.message;
                // Non è necessario impostare token qui, poiché viene impostato nel backend al momento della registrazione
                // state.token = action.payload.token;
                state.errors = {};
            })
            .addCase(registerUser.rejected, (state, action) => {
                state.status = 'failed';
                state.errors = action.payload || {};
            })
            // Update user
            .addCase(updateUser.pending, (state) => {
                state.status = 'loading';
                state.errors = {};
            })
            .addCase(updateUser.fulfilled, (state, action) => {
                state.status = 'succeded';
                state.user = action.payload.data;
                state.message = action.payload.message;
            })
            .addCase(updateUser.rejected, (state, action) => {
                state.status = 'failed';
                state.errors = action.payload || {};
            })
            // Fetch sessions
            .addCase(fetchSessions.pending, (state) => {
                state.sessionsLoading = true;
            })
            .addCase(fetchSessions.fulfilled, (state, action) => {
                state.sessions = action.payload;
                state.sessionsLoading = false;
            })
            .addCase(fetchSessions.rejected, (state) => {
                state.sessionsLoading = false;
            })
            // Fetch profile
            .addCase(fetchProfile.pending, (state) => {
                state.status = 'loading';
                state.errors = {};
            })
            .addCase(fetchProfile.fulfilled, (state, action) => {
                state.status = 'succeded';
                state.user = action.payload.data;
                state.message = action.payload.message || 'Profilo ricaricato con successo';
                state.errors = {};
            })
            .addCase(fetchProfile.rejected, (state, action) => {
                state.status = 'failed';
                state.errors = action.payload || {};
            });
    }
});

export const { removeSession, removeAllOtherSessions, updateAvatar } = userSlice.actions;

//export const { logoutUser } = userSlice.actions;
export default userSlice.reducer;
