import React, { useState, useEffect } from 'react'
import Navbar from './Navbar'
import Sidebar from './Sidebar'

const BaseLayout = ({ className = null, children }) => {
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [isMobile, setIsMobile] = useState(window.innerWidth < 992);

    useEffect(() => {
        const handleResize = () => {
            const mobile = window.innerWidth < 992;
            setIsMobile(mobile);
            // Su desktop, la sidebar è sempre visibile (non serve lo stato open)
            if (!mobile) {
                setSidebarOpen(false);
            }
        };

        window.addEventListener('resize', handleResize);
        handleResize(); // Chiamata iniziale

        return () => window.removeEventListener('resize', handleResize);
    }, []);

    // Blocca lo scroll del body quando la sidebar è aperta su mobile
    useEffect(() => {
        if (isMobile && sidebarOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
        }

        // Cleanup quando il componente viene smontato
        return () => {
            document.body.style.overflow = '';
        };
    }, [isMobile, sidebarOpen]);

    const toggleSidebar = () => {
        setSidebarOpen(!sidebarOpen);
    };

    const closeSidebar = () => {
        setSidebarOpen(false);
    };

    return (
        <>
            {/* Sidebar - visibile su desktop, drawer su mobile */}
            <Sidebar 
                isOpen={sidebarOpen || !isMobile} 
                onClose={closeSidebar}
            />

            {/* Contenuto principale */}
            <main 
                id="main_scheda_app" 
                className={`app-main ${!isMobile ? 'app-main--with-sidebar' : ''}`}
            >
                <div className="app-main__container">
                        {children}
                </div>
            </main>

            {/* Navbar - solo su mobile */}
            {isMobile && <Navbar onToggleSidebar={toggleSidebar} />}
        </>
    )
}

export default BaseLayout
