import React, { useMemo } from 'react';

const ExerciseStats = ({ data }) => {
    const stats = useMemo(() => {
        if (!data || data.length === 0) {
            return {
                totalSessions: 0,
                maxWeight: 0,
                maxReps: 0,
                totalVolume: 0
            };
        }

        // Calcola il peso massimo tra tutte le sessioni
        const maxWeight = Math.max(...data.map(session => session.maxWeight || 0));
        
        // Calcola le ripetizioni massime tra tutte le sessioni
        const maxReps = Math.max(...data.map(session => session.maxReps || 0));
        
        // Calcola il volume totale sommando il volume di tutte le sessioni
        const totalVolume = data.reduce((sum, session) => sum + (session.totalVolume || 0), 0);

        return {
            totalSessions: data.length,
            maxWeight,
            maxReps,
            totalVolume
        };
    }, [data]);

    return (
        <div className="exercise-stats">
            <div className="stat-item">
                <div className="stat-value">{stats.totalSessions}</div>
                <div className="stat-label">Sessioni</div>
            </div>
            <div className="stat-item">
                <div className="stat-value">{stats.maxWeight} kg</div>
                <div className="stat-label">Peso Max</div>
            </div>
            <div className="stat-item">
                <div className="stat-value">{stats.maxReps}</div>
                <div className="stat-label">Reps Max</div>
            </div>
            <div className="stat-item">
                <div className="stat-value">{stats.totalVolume} kg</div>
                <div className="stat-label">Volume Totale</div>
            </div>
        </div>
    );
};

export default ExerciseStats;
