import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import AuthLayout from '../../components/AuthLayout';
import { InputError } from '../../components/FormComponents';
import { useValidationSystem } from '../../hooks/useValidationSystem';
import { useDispatch, useSelector } from "react-redux";
import { registerUser } from '../../features/user/userSlice';
import { toast } from 'react-toastify';


export const Register = () => {
    const navigate = useNavigate();
    const dispatch = useDispatch();
    const { status, message, token, errors: registerErrors } = useSelector((state) => state.user);
    const { loading } = useSelector((state) => state.loader);
    const [passwordVisible, setPasswordVisible] = useState(false);

    const initState = {
        username: '',
        email: '',
        password: '',
        password_confirmation: ''
    };

    const validations = [
        {
            name: 'username',
            required: true,
            min: 3,
            max: 50
        },
        {
            name: 'email',
            required: true,
            extra: 'email'
        },
        {
            name: 'password',
            required: true,
            extra: 'password'
        },
        {
            name: 'password_confirmation',
            required: true,
            extra: 'password_confirmation'
        }
    ];

    const [data, dataToSend, setData, errors, setErrors, validate] = useValidationSystem({ initState, validations, });

    const onInputHandler = (e) => {
        e.preventDefault();
        const { name, value } = e.target;
        setData((prev) => ({ ...prev, [name]: value }));
    };

    const onSubmitHandler = (e) => {
        e.preventDefault();
        if (!validate()) return;

        dispatch(registerUser(dataToSend));
    };

    /* UseEffect sugli errori del form ricevuti dal backend */
    useEffect(() => {
        setErrors(registerErrors.errors || {});
        toast.error(registerErrors.message);
    }, [registerErrors]);

    useEffect(() => {
        if (status === "succeded") {
            toast.success(message);
            navigate('/login');
        }
    }, [status, message]);

    /* Se sono già autenticato ma per sbaglio vado su /register */
    useEffect(() => {
        if (!!token) navigate('/workouts/last');
    }, [token]);

    return (
        <AuthLayout>
            <div className="card-auth">
                <div className="logo"></div>
                <h2>Registrati</h2>
                <h3>Unisciti a noi!</h3>
                <form className="form">
                    <div>
                        <div className="input-box">
                            <i className="fa-regular fa-user"></i>
                            <input name="username" type="text"
                                placeholder="Inserisci il tuo username" autoComplete="username"
                                value={data.username} onChange={onInputHandler} />
                        </div>
                        <InputError error={errors.username} />
                    </div>

                    <div>
                        <div className="input-box">
                            <i className="fa-regular fa-envelope"></i>
                            <input name="email" type="email"
                                placeholder="Inserisci la tua e-mail" autoComplete="email"
                                value={data.email} onChange={onInputHandler} />
                        </div>
                        <InputError error={errors.email} />
                    </div>

                    <div>
                        <div className="input-box">
                            <i className="fa-solid fa-lock"></i>
                            <input name="password"
                                type={passwordVisible ? "text" : "password"}
                                placeholder="Inserisci la tua password"
                                autoComplete="new-password" value={data.password}
                                onChange={onInputHandler} />
                            <button
                                type="button"
                                onClick={() => setPasswordVisible(!passwordVisible)}
                                className="btn-toggle-password"
                            >
                                <i className={passwordVisible ? "fas fa-eye" : "fas fa-eye-slash"}></i>
                            </button>
                        </div>
                        <InputError error={errors.password} />
                    </div>

                    <div>
                        <div className="input-box">
                            <i className="fa-solid fa-lock"></i>
                            <input name="password_confirmation"
                                type="password"
                                placeholder="Conferma la tua password"
                                autoComplete="new-password" value={data.password_confirmation}
                                onChange={onInputHandler} />
                        </div>
                        <InputError error={errors.password_confirmation} />
                    </div>

                    <button className="submit" onClick={onSubmitHandler} disabled={loading}>
                        {loading ? (
                            <i className="fa fa-spinner fa-spin"></i>
                        ) : (
                            "Registrati"
                        )}
                    </button>
                </form>
                <footer>Hai già un account? Accedi <Link to="/login">qui</Link></footer>
            </div>
        </AuthLayout>
    )
}

export default Register;
