import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import { hideLoader, showLoader } from "../loader/loaderSlice";
import { SchedaService } from "../../services/scheda.service";
import { toast } from "react-toastify";

const initialState = () => {

    return {
        workout: {},
        sessions: {},
        latestWorkoutId: null,
        workoutList: [],
        workoutListStatus: 'idle',
        status: 'idle',
        errors: {}
    }
};

// Thunk per la chiamata asincrona per ottenere l'ultima scheda per l'utente loggato
export const lastScheda = createAsyncThunk(
    'workout/lastScheda',
    async (_, { dispatch, rejectWithValue }) => {
        const cachedData = { ...SchedaService.getLatestWorkout() };
        if (!!Object.keys(cachedData).length) {
            return cachedData;
        }

        try {
            dispatch(showLoader()); // Mostra il loader all'inizio
            const { data } = await SchedaService.last();
            SchedaService.setScheda(data);

            return data;
        } catch (error) {
            return rejectWithValue(error.response.data);
        } finally {
            dispatch(hideLoader());
        }
    }
);

export const fetchWorkout = createAsyncThunk(
    'workout/fetchWorkout',
    async (id, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader()); // Mostra il loader all'inizio
            const { data } = await SchedaService.read({ id });

            return data;
        } catch (error) {
            return rejectWithValue(error.response);
            // return rejectWithValue(error.response.data);
        } finally {
            dispatch(hideLoader());
        }
    }
);

export const saveUpdatedNote = createAsyncThunk(
    'workout/saveUpdatedNote',
    async ({ exerciseId, value, isLatest = false }, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader()); // Mostra il loader all'inizio
            const { data } = await SchedaService.updateNote({ id: exerciseId, value });
            toast.success(data.message);
            return { ...data, isLatest };
        } catch (error) {
            return rejectWithValue(error.response.data);
        } finally {
            dispatch(hideLoader());
        }
    }
);

// Thunk per recuperare la lista di tutti i workout dell'utente
export const fetchWorkoutList = createAsyncThunk(
    'workout/fetchWorkoutList',
    async (_, { dispatch, rejectWithValue }) => {
        try {
            dispatch(showLoader());
            const { data } = await SchedaService.allUser();
            toast.success(data.message);
            return data.data;
        } catch (error) {
            return rejectWithValue(error.response?.data || { message: error.message });
        } finally {
            dispatch(hideLoader());
        }
    }
);

const workoutSlice = createSlice({
    name: 'workout',
    initialState,
    reducers: {
        resetWorkout: (state, action) => {
            state.workout = initialState
        },
        updateNote: (state, action) => {
            const { day, exerciseId, value = "" } = action.payload || {};

            // Trova l'array degli esercizi del gruppo muscolare nel giorno specifico
            const exercises = state.workout?.esercizi_x_day?.[day];

            if (exercises) {
                const exercise = state.workout.esercizi_x_day[day].find(ex => ex.id === exerciseId);
                if (exercise) {
                    exercise.noteEsercizio = value;
                }
            }
        },
        createDaySession: (state, action) => {
            const { day, sessions: items = [] } = action.payload || {};

            if (
                state.sessions?.[day]) {
                state.sessions[day] = [...state.sessions[day], ...items];
            }
        },
        updateSession: (state, action) => {
            const { day, updatedSession = {} } = action.payload || {};
            const daySessions = state.sessions?.[day];
            if (!daySessions) return;

            const exerciseSessionIndex = state.sessions[day].findIndex(s =>
                s.session_id === updatedSession.session_id &&
                s.protocol_exercise_id === updatedSession.protocol_exercise_id
            );

            if (exerciseSessionIndex !== -1) {
                state.sessions[day][exerciseSessionIndex] = { ...state.sessions[day][exerciseSessionIndex], ...updatedSession };
            }
        },
        clearErrors: (state) => {
            state.errors = {};
        },
        clearWorkoutList: (state) => {
            state.workoutList = [];
            state.workoutListStatus = 'idle';
        }
    },
    extraReducers: (builder) => {
        builder
            // last scheda
            .addCase(lastScheda.pending, (state) => {
                state.status = 'loading';
                state.latestWorkoutId = null;
                state.errors = {};
            })
            .addCase(lastScheda.fulfilled, (state, action) => {
                const { sessioni = {}, ...workout } = action.payload;

                state.status = 'succeeded';
                state.workout = workout;
                state.sessions = sessioni;
                state.latestWorkoutId = action.payload.idScheda;
                state.errors = {};
            })
            .addCase(lastScheda.rejected, (state, action) => {
                state.status = 'failed';
                state.workout = {};
                state.latestWorkoutId = null;
                state.errors = action.payload || {};
            })
            // scheda by id
            .addCase(fetchWorkout.pending, (state) => {
                state.status = 'loading';
                state.latestWorkoutId = null;
                state.errors = {};
            })
            .addCase(fetchWorkout.fulfilled, (state, action) => {
                const { sessioni = {}, ...workout } = action.payload;

                state.status = 'succeeded';
                state.workout = workout;
                state.sessions = sessioni;
                state.latestWorkoutId = null;
                state.errors = {};
            })
            .addCase(fetchWorkout.rejected, (state, action) => {
                state.status = 'failed';
                state.workout = {};
                state.sessions = {};
                state.latestWorkoutId = null;
                if (typeof action.payload.data === 'object') {
                    state.errors = {
                        statusCode: action.payload.status,
                        ...action.payload.data
                    }
                } else {
                    state.errors = {}
                }
            })
            // Aggiornamento note..
            .addCase(saveUpdatedNote.pending, (state) => {
                state.status = 'loading';
                state.errors = {};
            })
            .addCase(saveUpdatedNote.fulfilled, (state, action) => {
                state.status = 'succeeded';
                state.errors = {};
            })
            .addCase(saveUpdatedNote.rejected, (state, action) => {
                state.status = 'failed';
                state.errors = action.payload || {};
            })
            // Lista workout
            .addCase(fetchWorkoutList.pending, (state) => {
                state.workoutListStatus = 'loading';
            })
            .addCase(fetchWorkoutList.fulfilled, (state, action) => {
                state.workoutListStatus = 'succeeded';
                state.workoutList = action.payload;
            })
            .addCase(fetchWorkoutList.rejected, (state, action) => {
                state.workoutListStatus = 'failed';
                state.workoutList = [];
            })
    }
});

export const { resetWorkout, updateNote, createDaySession, updateSession, clearErrors, clearWorkoutList } = workoutSlice.actions;
export default workoutSlice.reducer;
