import React, { useEffect } from 'react';
import { Col, Row } from 'react-bootstrap';
import { useDispatch, useSelector } from 'react-redux';
import { toast } from 'react-toastify';
import { fetchWorkoutList } from '../features/workout/workoutSlice';
import BaseLayout from '../components/BaseLayout';
import PageHeader from '../components/PageHeader';
import { Link, useNavigate } from 'react-router-dom';

const WorkoutList = () => {
    const navigate = useNavigate();
    const dispatch = useDispatch();
    const { workoutList, workoutListStatus } = useSelector(state => state.workout);

    useEffect(() => {
        document.title = "I miei Workouts";
        // Carica i workout solo se non sono già presenti nello stato o se non sono in caricamento
        if (workoutList.length === 0 && workoutListStatus !== 'loading' && workoutListStatus !== 'succeeded') {
            dispatch(fetchWorkoutList()).unwrap().catch((error) => {
                toast.error(error.message || 'Errore nel recupero dei workout', {
                    onClose: () => {
                        navigate("/workouts/last");
                    },
                    onClick: () => {
                        navigate("/workouts/last");
                    }
                });
            });
        }
    }, [dispatch, navigate, workoutList.length, workoutListStatus]);

    return (
        <BaseLayout>
            <div className="page-content">
                <PageHeader
                    title="I miei Workouts"
                    subtitle="Visualizza e gestisci tutti i tuoi piani di allenamento"
                />

                <Row className="g-4">
                    {workoutList.map((workout) => (
                        <Col key={workout.idScheda} md={4}>
                            <div className="workout-card">
                                <div className="workout-card__header">
                                    <div className="workout-card__icon">
                                        <i className="fa-solid fa-dumbbell"></i>
                                    </div>
                                    <h3 className="workout-card__title">{workout.nomeScheda}</h3>
                                </div>
                                <div className="workout-card__body">
                                    <div className="workout-card__info">
                                        <div className="workout-card__info-item">
                                            <i className="fa-solid fa-bullseye"></i>
                                            <div>
                                                <span className="workout-card__info-label">Allenamenti</span>
                                                <span className="workout-card__info-value">{workout.numeroAllSettimanali || 'ND'}/settimana</span>
                                            </div>
                                        </div>
                                        <div className="workout-card__info-item">
                                            <i className="fa-solid fa-calendar-days"></i>
                                            <div>
                                                <span className="workout-card__info-label">Scadenza</span>
                                                <span className="workout-card__info-value">{new Date(workout.dataDiScadenza).toLocaleDateString('it-IT', { day: '2-digit', month: 'short', year: 'numeric' })}</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div className="workout-card__footer">
                                    <Link 
                                        to={`/workouts/${workout.idScheda}`}
                                        className="workout-card__link"
                                    >
                                        Apri scheda <i className="fa-solid fa-arrow-right"></i>
                                    </Link>
                                </div>
                            </div>
                        </Col>
                    ))}
                </Row>
            </div>
        </BaseLayout>
    );
};

export default WorkoutList;
