import React, { useEffect } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import BaseLayout from '../components/BaseLayout';
import SchedaHeader from '../components/SchedaHeader';
import { clearErrors, fetchWorkout, lastScheda } from '../features/workout/workoutSlice';
import { Link, useLocation, useNavigate, useParams } from 'react-router-dom';
import { SchedaService } from '../services/scheda.service';

const Scheda = () => {
    const dispatch = useDispatch();
    const location = useLocation();
    const navigate = useNavigate();
    const { id = null } = useParams();
    const { workout, latestWorkoutId, errors } = useSelector(state => state.workout);
    const { loading } = useSelector(state => state.loader);

    /**
     * Restituisce i gruppi muscolari di un allenamento, presi una sola volta.
     */
    const getMuscleGroups = (exercises) => {
        const exercisesGroups = exercises.map(e => e.gruppoMuscolare)
        return [...new Set(exercisesGroups)].join(', ');
    }

    const handleReloadData = () => {
        if (!!id) {
            dispatch(fetchWorkout(id));
        } else {
            SchedaService.clearWorkout();
            dispatch(lastScheda());
        }
    }

    useEffect(() => {
        if (!!id) {
            if (!!workout.idScheda && workout.idScheda == id) return;

            dispatch(fetchWorkout(id));
        } else {
            if (!!workout.idScheda && workout.idScheda === latestWorkoutId) return;

            dispatch(lastScheda());
        }
    }, [dispatch, id]);

    useEffect(() => {
        if (!!Object.keys(errors).length) {
            const { status_code: code, message, info, cta, redirect_link } = errors;
            // resetto l'oggetto errors..
            dispatch(clearErrors());

            if (redirect_link) {
                navigate(redirect_link);
            } else {
                // Reindirizza alla pagina di errore
                navigate("/error", {
                    state: {
                        code,
                        message,
                        cta: {
                            description: info || null,
                            actionLabel: cta?.label || "Ritorna alla home",
                            route: cta?.action || "/workouts/last"
                        }
                    }
                });
            }
        }
    }, [errors]);

    if (!workout.idScheda) return <></>;
    
    const progressPath = id ? `/progress/${id}` : '/progress';
    
    return (
        <BaseLayout>
            <div className="page-content">
                <SchedaHeader
                    workout={workout}
                    progressPath={progressPath}
                    handleReloadData={handleReloadData}
                    loading={loading}
                />
            </div>
            <section className="protocol-page">

                {Object.entries(workout.esercizi_x_day).map(([day, exercises]) => (
                    <div className="card card-riepilogo-scheda" key={day}>
                        <div className="card-body">
                            <div className="d-flex justify-content-between">
                                <div className="d-flex align-items-center">
                                    <div className="box day-box me-3">{day}</div>

                                    <div>
                                        <h5 className="specs-title mb-1">{getMuscleGroups(exercises)}</h5>
                                        <p className="specs-sub-title"><i className="fa-solid fa-dumbbell"></i> {exercises.length} <span>esercizi</span></p>
                                    </div>
                                </div>

                                <Link to={`${location.pathname}/day/${day}`} className="box arrow-box">
                                    <i className="fa-solid fa-chevron-right"></i>
                                </Link>
                            </div>
                        </div>
                    </div>
                ))}
            </section>
        </BaseLayout>
    )
}

export default Scheda
