import { useState } from "react";
import { capitalize } from '../functions';

export const useValidationSystem = ({ initState, validations }) => {
    const [data, setData] = useState(initState);
    const [errors, setErrors] = useState({});
    const dataToSend = { ...data }; //Creo un clone dell'oggetto data
    const emailMatch = (value) => {
        return value.match(
            /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        );
    }

    const phoneMatch = (value) => {
        return value.match(/^\d{10}$/);
    }

    const isNumber = (myVar) => {
        return !isNaN(myVar);
        //return (typeof value === 'number' && !Number.isNaN(value))
    }

    /* Funzione che effettua il trim delle stringhe */
    const sanitizeObject = (object) => {
        for (const key in object) {
            let value = object[key];
            //value = value?.trim(); // vecchio metodo, tratta tutti i valori ricevuti come se fossero stringhe
            if (value && typeof value === 'string') object[key] = value.trim();
        }
    }

    const validate = () => {
        const formErrors = {};
        let tempPassword = '';
        sanitizeObject(dataToSend); //Richiamo la funzione che mi effettua un trim sui dati di input

        validations.forEach(input => {
            const { name, required, min, max, extra, labelError } = input;
            let inputValue = dataToSend[name]; //Recupero il valore dell'input corrente dall'oggetto di appoggio

            // Validazione sul required..
            if (required && !inputValue) {
                formErrors[name] = labelError ? `${labelError} è obbligatorio.` : `${capitalize(name)} è obbligatorio.`;
            }

            //Validazione sul min..
            if (inputValue && inputValue.length < min) {
                formErrors[name] = labelError ? `${labelError} deve essere lungo almeno ${min} caratteri.` : `${capitalize(name)} deve essere lungo almeno ${min} caratteri.`;
            }

            //Validazione sul max..
            if (inputValue && inputValue.length > max) {
                formErrors[name] = labelError ? `${labelError} non deve superare ${max} caratteri.` : `${capitalize(name)} non deve superare ${max} caratteri.`;
            }

            //Validazione tipo Email..
            if (inputValue && extra === 'email' && !emailMatch(inputValue)) {
                formErrors[name] = 'La mail non è valida.';
            }

            //Validazione tipo Number..
            if (inputValue && extra === 'number' && !isNumber(inputValue)) {
                formErrors[name] = labelError ? `${labelError} deve essere un numero intero.` : `${capitalize(name)} deve essere un numero intero.`;
            }

            //Memorizzo la password temporaneamente
            if (inputValue && extra === 'password') {
                tempPassword = inputValue;
            }

            //Confronto la password con la sua conferma
            if (inputValue && extra === 'password_confirmation' && inputValue != tempPassword) {
                formErrors['password'] = 'Le password non coincidono.';
                formErrors[name] = 'Le password non coincidono.';
            }

            //Validazione del numero di telefono..
            if (inputValue && extra === 'phone' && !phoneMatch(inputValue)) {
                formErrors[name] = 'Numero di telefono non valido.';
            }

            //Elimino spazi superflui dal campo address..
            if (inputValue && extra === 'address') {
                const newValue = inputValue.replace(/\s\s+/g, ' ');
                dataToSend[name] = newValue;
            }
        });

        setData(dataToSend); //Aggiorno i dati del form con quelli appena validati..
        setErrors(formErrors);
        return Object.keys(formErrors).length === 0;
    };

    return [data, dataToSend, setData, errors, setErrors, validate];
}