import { useState, useEffect, useRef } from 'react';

const WorkoutTimer = ({ seconds = 30 }) => {
	const [timeLeft, setTimeLeft] = useState(seconds);
	const [isActive, setIsActive] = useState(false);
	const [isComplete, setIsComplete] = useState(false);
	const audioRef = useRef(null);
	const wakeLockRef = useRef(null);

	// Calcola la percentuale di tempo rimanente
	const percentage = (timeLeft / seconds) * 100;

	// Calcola i valori per l'SVG del cerchio
	const radius = 45;
	const circumference = 2 * Math.PI * radius;
	const strokeDashoffset = circumference * (1 - percentage / 100);

	// Formatta il tempo rimanente in minuti:secondi
	const formatTime = (time) => {
		const minutes = Math.floor(time / 60);
		const seconds = time % 60;
		return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
	};

	// Gestisce il Wake Lock (impedisce lo standby)
	const requestWakeLock = async () => {
		try {
			if ('wakeLock' in navigator) {
				wakeLockRef.current = await navigator.wakeLock.request('screen');
				// console.log('Wake Lock attivato con successo!');
			}
		} catch (err) {
			// console.error(`Errore Wake Lock: ${err.message}`);
		}
	};

	const releaseWakeLock = () => {
		// Rilascia il wake lock se esiste
		if (wakeLockRef.current) {
			wakeLockRef.current.release()
				.then(() => {
					// console.log('Wake Lock rilasciato');
					wakeLockRef.current = null;
				})
				.catch(err => console.error('Errore rilascio Wake Lock:', err));
		}
	};

	// Gestisce il timer
	useEffect(() => {
		let interval = null;

		if (isActive && timeLeft > 0) {
			interval = setInterval(() => {
				setTimeLeft(timeLeft => timeLeft - 1);
			}, 1000);
		} else if (isActive && timeLeft === 0) {
			setIsActive(false);
			setIsComplete(true);

			// Riproduci il suono quando il timer finisce
			if (audioRef.current) {
				audioRef.current.play();
			}

			// Rilascia il WakeLock
			releaseWakeLock();
		}

		return () => clearInterval(interval);
	}, [isActive, timeLeft]);

	// Gestisce il documento quando va in visibilità nascosta
	useEffect(() => {
		const handleVisibilityChange = () => {
			if (document.visibilityState === 'visible' && isActive) {
				requestWakeLock();
			}
		};

		document.addEventListener('visibilitychange', handleVisibilityChange);

		return () => {
			document.removeEventListener('visibilitychange', handleVisibilityChange);
		};
	}, [isActive]);

	// Funzione per avviare o mettere in pausa il timer
	const toggleTimer = async () => {
		if (!isActive) {
			setIsActive(true);
			setIsComplete(false);
			await requestWakeLock();
		} else {
			setIsActive(false);
			releaseWakeLock();
		}
	};

	// Funzione per resettare il timer
	const resetTimer = () => {
		setIsActive(false);
		setIsComplete(false);
		setTimeLeft(seconds);
		releaseWakeLock();

		// Ferma la riproduzione audio se è in corso
		if (audioRef.current) {
			audioRef.current.pause();
			audioRef.current.currentTime = 0;
		}
	};

	return (
		<div className="timer-container-version2 d-flex flex-column align-items-center justify-content-center w-100 mx-auto p-4">
			{/* Audio per la suoneria */}
			<audio
				ref={audioRef}
				src="/app/sounds/timer.wav"
				preload="auto"
				// loop
			/>

			{/* Timer circolare */}
			<div className="timer position-relative mb-4">
				<svg className="w-100 h-100" style={{ transform: 'rotate(-90deg)' }} viewBox="0 0 100 100">
					{/* Cerchio di sfondo */}
					<circle
						cx="50"
						cy="50"
						r={radius}
						stroke="#e2e8f0"
						strokeWidth="4"
						fill="none"
					/>

					{/* Cerchio del progresso */}
					<circle
						cx="50"
						cy="50"
						r={radius}
						stroke={isComplete ? "#10b981" : isActive ? "#cb3234" : "#94a3b8"}
						strokeWidth="4"
						fill="none"
						strokeDasharray={circumference}
						strokeDashoffset={strokeDashoffset}
						strokeLinecap="round"
					/>
				</svg>

				{/* Testo del timer */}
				<div className="position-absolute top-0 start-0 end-0 bottom-0 d-flex flex-column align-items-center justify-content-center">
					<span className="display-4 fw-bold">{formatTime(timeLeft)}</span>
					<span className="text-secondary mt-2 small">
						{isComplete ? "Completato!" : isActive ? "In corso..." : "Pronto"}
					</span>
				</div>
			</div>

			{/* Pulsanti di controllo */}
			<div className="d-flex">
				<button
					onClick={toggleTimer}
					className={`btn btn-control me-3 ${isActive ? "btn-outline-primary" : "btn-primary"}`}>
					{isActive ? (
						<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" className="bi bi-pause-fill" viewBox="0 0 16 16">
							<path d="M5.5 3.5A1.5 1.5 0 0 1 7 5v6a1.5 1.5 0 0 1-3 0V5a1.5 1.5 0 0 1 1.5-1.5m5 0A1.5 1.5 0 0 1 12 5v6a1.5 1.5 0 0 1-3 0V5a1.5 1.5 0 0 1 1.5-1.5" />
						</svg>
					) : (
						<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" className="bi bi-play-fill" viewBox="0 0 16 16">
							<path d="m11.596 8.697-6.363 3.692c-.54.313-1.233-.066-1.233-.697V4.308c0-.63.692-1.01 1.233-.696l6.363 3.692a.802.802 0 0 1 0 1.393" />
						</svg>
					)}
				</button>

				<button
					onClick={resetTimer}
					className="btn btn-control btn-outline-secondary">
					<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" className="bi bi-arrow-counterclockwise" viewBox="0 0 16 16">
						<path fillRule="evenodd" d="M8 3a5 5 0 1 1-4.546 2.914.5.5 0 0 0-.908-.417A6 6 0 1 0 8 2z" />
						<path d="M8 4.466V.534a.25.25 0 0 0-.41-.192L5.23 2.308a.25.25 0 0 0 0 .384l2.36 1.966A.25.25 0 0 0 8 4.466" />
					</svg>
				</button>
			</div>
		</div>
	);
}

export default WorkoutTimer;